const items = $input.all().map(i => i.json);
const normalize = v => String(v ?? "").trim();

// Identify sheet rows (they have row_number from Google Sheets)
const sheetRows = items.filter(i => i.row_number !== undefined);

// Identify API rows (they DO NOT have row_number)
const apiRows = items.filter(i => i.row_number === undefined && i.member_id);

// Build existing member_id set
const existingIds = new Set(
  sheetRows
    .map(r => normalize(r.member_id))
    .filter(id => id)
);

// Filter API rows
const newRows = apiRows.filter(r => {
  const id = normalize(r.member_id);
  return id && !existingIds.has(id);
});

// Output only new ones
return newRows.map(r => ({ json: r }));

const eventId = $json.event_id || $json["Event ID"];

return $json.data.map(p => ({
  json: {
    ...p,
    event_id: eventId
  }
}));

const raw = $json.data;
const parsed = JSON.parse(raw);

// Filter desired events
const filtered = parsed.data.filter(r =>
  ["1084", "1085"].includes(r.event_id)
);

// Combine into one string
const combinedEventIds = filtered.map(r => r.event_id).join(",");

return [{
  json: {
    member_id: parsed.data[0].member_id,
    event_ids: combinedEventIds
  }
}];
